    vec3 outColor = ambient + Lo + EMISSIVE;

    outColor = outColor / (outColor + vec3(1.0));   // Reinhard
    outColor = pow(outColor, vec3(1.0 / 2.2));        // gamma
    color = vec4(outColor, 1.0);




    // __APPLY_OVERLAY_FILTERS__
}

